import itertools, random, subprocess, json
from collections import deque

BOARD_SIZE = 4
ACTIONS = [
    'D0','D1','D2','D3',
    'L0','L1','L2','L3',
    'R0','R1','R2','R3',
    'U0','U1','U2','U3',
]
KIND = {a: ('row' if a[0] in 'LR' else 'col') for a in ACTIONS}
INV = {**{f'R{i}':f'L{i}' for i in range(4)}, **{f'L{i}':f'R{i}' for i in range(4)}, **{f'D{i}':f'U{i}' for i in range(4)}, **{f'U{i}':f'D{i}' for i in range(4)}}
RANK = {a:i for i,a in enumerate(ACTIONS)}
MOD = 4

def idx(r,c): return r*4+c

def shift_row(board,row,amount):
    amount %= 4
    if amount == 0: return
    s = row*4
    vals = board[s:s+4]
    board[s:s+4] = vals[-amount:] + vals[:-amount]

def shift_col(board,col,amount):
    amount %= 4
    if amount == 0: return
    vals = [board[idx(r,col)] for r in range(4)]
    vals = vals[-amount:] + vals[:-amount]
    for r,v in enumerate(vals):
        board[idx(r,col)] = v

