    board = list(state)
    i = int(action[1])
    if action[0] == 'R':
        s = i*4
        for j in range(4): board[s+j] = (board[s+j] + 1) % MOD
        shift_row(board, i, 1)
    elif action[0] == 'L':
        shift_row(board, i, -1)
        s = i*4
        for j in range(4): board[s+j] = (board[s+j] - 1) % MOD
