        shift_col(board, i, -1)
        for r in range(4): board[idx(r,i)] = (board[idx(r,i)] - 1) % MOD
    return tuple(board)

def changes(seq):
    return sum(KIND[a] != KIND[b] for a,b in zip(seq,seq[1:]))

def key(seq):
    return (len(seq), changes(seq), tuple(RANK[a] for a in seq))

def brute(board):
    zero = (0,)*16
    best = None
    q = deque([(board, [])])
    while q:
        state, seq = q.popleft()
        if state == zero:
            if best is None or key(seq) < key(best):
                best = seq
            continue
        if len(seq) == 5:
            continue
        for a in ACTIONS:
            nxt = apply(state, a)
            q.append((nxt, seq + [a]))
    return best

# Build reachable boards by random sequences from zero.
zero = (0,)*16
