    # overwrite board using sets so solver starts from this board
    events = []
    eid = 1
    at = 1
    for r in range(4):
        for c in range(4):
            events.append({'id':eid,'at':at,'op':'set','row':r,'col':c,'value':board[idx(r,c)]})
            eid += 1
            at += 1
    doc = {'size':4,'modulus':4,'chapters':[{'name':'x','events':events}]}
    proc = subprocess.run(['/app/solver'], input=json.dumps(doc).encode(), stdout=subprocess.PIPE, check=True)
    got = json.loads(proc.stdout)['solutions'][0]
